# ==============================================================================
# 1. ELEVAÇÃO AUTOMÁTICA DE PRIVILÉGIOS E POLÍTICA DE EXECUÇÃO
# ==============================================================================
$isAdmin = ([Security.Principal.WindowsPrincipal][Security.Principal.WindowsIdentity]::GetCurrent()).IsInRole([Security.Principal.WindowsBuiltInRole]::Administrator)

if (-not $isAdmin) {
    $scriptPath = $MyInvocation.MyCommand.Path
    if (-not $scriptPath) { $scriptPath = $PSCommandPath }

    try {
        # Relança o script como Administrador e aplica a política de execução Bypass para ele mesmo
        Start-Process powershell.exe -Verb RunAs -ArgumentList "-NoProfile -ExecutionPolicy Bypass -File `"$scriptPath`""
        Exit
    } catch {
        [System.Windows.Forms.MessageBox]::Show("Falha ao elevar privilégios. Execute como Administrador.", "Erro de Permissão", 0, 16)
        Exit
    }
}

# Define a política de execução como Bypass para a sessão atual (necessário para scripts internos como o Chocolatey)
Set-ExecutionPolicy Bypass -Scope Process -Force

