# Função para verificar e instalar Chocolatey silenciosamente
function Instalar-ChocoSilencioso() {
    if (-not (Get-Command choco -ErrorAction SilentlyContinue)) {
        $txtLogMs.AppendText("`r`n[!] Chocolatey não encontrado. Instalando automaticamente...`r`n"); $form.Refresh()
        try {
            Set-ExecutionPolicy Bypass -Scope Process -Force
            [System.Net.ServicePointManager]::SecurityProtocol = [System.Net.SecurityProtocolType]::Tls12
            Invoke-Expression ((New-Object System.Net.WebClient).DownloadString('https://community.chocolatey.org/install.ps1')) | Out-Null
            $txtLogMs.AppendText("[SUCESSO] Chocolatey instalado.`r`n"); $form.Refresh()
        } catch {
            $txtLogMs.AppendText("[ERRO] Falha ao instalar Chocolatey: $_`r`n"); $form.Refresh()
            return $false
        }
    }
    return $true
}

# Adicionando evento a todos os botões de aplicativos
foreach ($btn in $botoesMs) {
    $btn.Add_Click({
        $comando = $this.Tag
        $nomeApp = $this.Text
        
        $txtLogMs.AppendText("`r`n----------------------------------------`r`n")
        $txtLogMs.AppendText("Iniciando instalação: $nomeApp`r`n"); $form.Refresh()
        
        # Desabilita todos os botões temporariamente
        foreach ($b in $botoesMs) { $b.Enabled = $false }
        $btnAtivWinMs.Enabled = $false
        $btnAtivOffMs.Enabled = $false

        if (Instalar-ChocoSilencioso) {
            $txtLogMs.AppendText("Baixando e instalando (isso pode demorar minutos, aguarde)...`r`n"); $form.Refresh()
            try {
                # Executa o choco e captura a saída
                $processo = Start-Process cmd -ArgumentList "/c `"$comando`"" -Wait -PassThru -NoNewWindow
                
                if ($processo.ExitCode -eq 0 -or $processo.ExitCode -eq 1641 -or $processo.ExitCode -eq 3010) {
                    $txtLogMs.AppendText("[SUCESSO] Instalação concluída!`r`n")
                } else {
                    $txtLogMs.AppendText("[ERRO] Falha ou aviso. Código de saída: $($processo.ExitCode)`r`n")
                }
            } catch {
                $txtLogMs.AppendText("[ERRO] Exceção durante a execução: $_`r`n")
            }
        }

        # Reabilita botões
        foreach ($b in $botoesMs) { $b.Enabled = $true }
        $btnAtivWinMs.Enabled = $true
        $btnAtivOffMs.Enabled = $true
        $form.Refresh()
    })
}

