:"Ubisoft Connect","Descrição":"Serviço de jogos da Ubisoft.","Comando Chocolatey":"choco install \"ubisoft-connect\"","Comando Winget":"winget install \"Ubisoft.Connect\""},{"Categoria":"Games","Nome":"Virtual Desktop Streamer","Descrição":"Transmita o desktop para dispositivos VR.","Comando Chocolatey":"-","Comando Winget":"winget install \"VirtualDesktop.Streamer\""},{"Categoria":"Games","Nome":"XEMU","Descrição":"Emulador de Xbox original.","Comando Chocolatey":"-","Comando Winget":"winget install \"xemu-project.xemu\""}]
'@

$treeView = New-Object System.Windows.Forms.TreeView
$treeView.Location = New-Object System.Drawing.Point(15, 15)
$treeView.Size = New-Object System.Drawing.Size(480, 520)
$treeView.CheckBoxes = $true
$tabApps.Controls.Add($treeView)

$treeView.add_AfterCheck({
    param($sender, $e)
    if ($e.Action -ne [System.Windows.Forms.TreeViewAction]::Unknown) {
        foreach ($child in $e.Node.Nodes) { $child.Checked = $e.Node.Checked }
    }
})

$btnInstalar = New-Object System.Windows.Forms.Button
$btnInstalar.Text = "Instalar Programas Selecionados"
$btnInstalar.Location = New-Object System.Drawing.Point(15, 545)
$btnInstalar.Size = New-Object System.Drawing.Size(480, 45)
$btnInstalar.BackColor = [System.Drawing.Color]::LightSkyBlue
$btnInstalar.Font = New-Object System.Drawing.Font("Segoe UI", 10, [System.Drawing.FontStyle]::Bold)
$btnInstalar.Enabled = $false
$tabApps.Controls.Add($btnInstalar)

$statusApps = New-Object System.Windows.Forms.Label
$statusApps.Location = New-Object System.Drawing.Point(15, 610)
$statusApps.Size = New-Object System.Drawing.Size(480, 40)
$statusApps.Text = "Pronto para instalar. A lista já foi carregada automaticamente."
$statusApps.ForeColor = [System.Drawing.Color]::Green
$tabApps.Controls.Add($statusApps)

# Carrega a árvore automaticamente ao iniciar o form
$form.Add_Load({
    try {
        $appsData = $jsonString | ConvertFrom-Json
        $treeView.Nodes.Clear()
        
        $categorias = $appsData | Select-Object -ExpandProperty Categoria -Unique | Where-Object { ![string]::IsNullOrWhiteSpace($_) -and $_ -ne '-' }

        foreach ($cat in $categorias) {
            $nodeCat = $treeView.Nodes.Add($cat)
            $appsDaCat = $appsData | Where-Object { $_.Categoria -eq $cat }
            
            foreach ($app in $appsDaCat) {
                $nome = $app.Nome
                $cmdWinget = $app.'Comando Winget'
                $cmdChoco = $app.'Comando Chocolatey'

                if ($cmdWinget -ne "-" -and ![string]::IsNullOrWhiteSpace($cmdWinget)) {
                    $id = $cmdWinget -replace '(?i)winget install\s+', '' -replace '"', ''
                    $child = $nodeCat.Nodes.Add("$nome (Winget)")
                    $child.Tag = @{ Tipo = 'Winget'; ID = $id.Trim() }
                }
                elseif ($cmdChoco -ne "-" -and ![string]::IsNullOrWhiteSpace($cmdChoco)) {
                    $id = $cmdChoco -replace '(?i)choco install\s+', '' -replace '"', ''
                    $child = $nodeCat.Nodes.Add("$nome (Choco)")
                    $child.Tag = @{ Tipo = 'Choco'; ID = $id.Trim() }
                }
            }
        }
        $btnInstalar.Enabled = $true
    } catch {
        [System.Windows.Forms.MessageBox]::Show("Erro ao processar a lista interna de aplicativos.", "Erro", 0, 16)
    }
})

$btnInstalar.Add_Click({
    $selecionados = 0
    foreach ($nodeCat in $treeView.Nodes) {
        foreach ($nodeApp in $nodeCat.Nodes) { if ($nodeApp.Checked) { $selecionados++ } }
    }

    if ($selecionados -eq 0) {
        [System.Windows.Forms.MessageBox]::Show("Selecione ao menos um programa.", "Aviso", 0, 48)
        return
    }

    $btnInstalar.Enabled = $false
    $treeView.Enabled = $false

    foreach ($nodeCat in $treeView.Nodes) {
        foreach ($nodeApp in $nodeCat.Nodes) {
            if ($nodeApp.Checked -and $nodeApp.Tag) {
                $appTag = $nodeApp.Tag
                $id = $appTag.ID
                $nomeDisplay = $nodeApp.Text

                $statusApps.Text = "Instalando: $nomeDisplay..."
                $statusApps.ForeColor = [System.Drawing.Color]::Blue
                $form.Refresh()

                if ($appTag.Tipo -eq 'Winget') {
                    Start-Process -FilePath "winget" -ArgumentList "install --id `"$id`" --exact --silent --accept-package-agreements --accept-source-agreements" -Wait -NoNewWindow
                }
                elseif ($appTag.Tipo -eq 'Choco') {
                    Start-Process -FilePath "choco" -ArgumentList "install `"$id`" -y" -Wait -NoNewWindow
                }
            }
        }
    }
    
    $statusApps.Text = "Instalações concluídas!"
    $statusApps.ForeColor = [System.Drawing.Color]::Green
    [System.Windows.Forms.MessageBox]::Show("Processo finalizado!", "Concluído", 0, 64)
    
    $btnInstalar.Enabled = $true
    $treeView.Enabled = $true
})

# Exibe a janela
$form.ShowDialog() | Out-Null
